import{_ as e,c as a,o,a as r}from"./app.1cfac776.js";const _=JSON.parse('{"title":"Profesores","description":"","frontmatter":{},"headers":[],"relativePath":"ense\xF1anza/profesores.md"}'),s={name:"ense\xF1anza/profesores.md"},i=r('<h1 id="profesores" tabindex="-1">Profesores <a class="header-anchor" href="#profesores" aria-hidden="true">#</a></h1><p>IesApp permite mantener la informaci\xF3n completa del claustro. Es un sistema de directorio que permite a todo el claustro localizar el correo corporativo de los compa\xF1eros, identificarlo mediante la orla de fotos.</p><p><strong>Plantilla</strong></p><p>Adem\xE1s de ese servicio sencillo de directorio nos permite definir la <strong>plantilla</strong> actual en cada momento. Esta informaci\xF3n s\xF3lo es visibe para jefatura. La plantilla est\xE1 definida para cada curso y cada profesor ocupa una plaza de forma fija, de forma interina (de plantilla sin titular, de cupo sin titular o reserva del titular) o mediante sustituci\xF3n. Esta informaci\xF3n que esb\xE1sica no est\xE1 en ning\xFAn sitio de los sistemas oficiales.</p><p><strong>Horario</strong></p><p>La informaci\xF3n fundamental que tenemos de cada profesor es su horario. Los horarios se importan con el mismo fichero que genera Pe\xF1alara para SIGAD. Es una pieza fundamental para el funcionamiento del centro:</p><ul><li>Est\xE1n siempre actualizados y disponibles para todo el claustro y conserjer\xEDa.</li><li>Son la base del sistema de guardias</li><li>IesApp tambi\xE9n ayuda con la modificaci\xF3n de horarios (FCT/FEOE) de forma coordinada entre jefatura y los profesores interesados.</li></ul><p><strong>Correo corporativo</strong></p><ul><li>IesApp genera un nombre \xFAnico de correo corporativo. Evita duplicidades y aplica siempre un criterio.</li><li>Adem\xE1s genera los ficheros csv que permite dar de alta a todos los usuarios nuevos.</li><li>Los grupos de correo son algo cotidiano en todas las organizaciones. Mantenerlos actualizados es una tarea laboriosa y no siempre sencilla de realizar. IesApp permite que los profesores se asocien a los grupos en los que tiene inter\xE9s. IesApp genera tambi\xE9n el fichero csv para mantener los grupos de correo actualizados en los servicios de Google Workspace.</li></ul>',9),n=[i];function t(l,c,d,p,u,m){return o(),a("div",null,n)}const g=e(s,[["render",t]]);export{_ as __pageData,g as default};
